import { resolvePath } from "@typespec/compiler";
import { createTester } from "@typespec/compiler/testing";

/**
 * Shared tester for all @a10n/blueprint-typespec tests.
 * Automatically imports the library and brings State namespace into scope.
 */
export const Tester = createTester(resolvePath(import.meta.dirname, "../.."), {
  libraries: ["@a10n/blueprint-typespec", "@a10n/typespec-dbml"],
})
  .importLibraries()
  .using("State");
